// Generate all 50 template blocks
let allTemplates = '';
try {
  for (const def of tmplDefs) {
    const t = generateTemplate(def);
    allTemplates += t;
  }
  fs.writeFileSync('gen_debug.txt', 'templates_len=' + allTemplates.length + '\nfirst100=' + allTemplates.slice(0, 100));
} catch(e) {
  fs.writeFileSync('gen_debug.txt', 'ERROR in loop: ' + e.message + '\n' + e.stack);
  process.exit(1);
}

// The last template (73) becomes the `else` fallback
// We need to change "else if (templateIndex === 73)" to "else"
allTemplates = allTemplates.replace(
  /else if \(templateIndex === 73\) \{/,
  'else {'
);

// Find where to insert: after template 23's closing brace, before the privacy injection
const insertMarker = `  // Injeta bloco de Privacidade/Termos antes de fechar o body`;
const insertIdx = content.indexOf(insertMarker);

fs.appendFileSync('gen_debug.txt', '\ninsertIdx=' + insertIdx);

if (insertIdx === -1) {
  console.error('ERROR: Could not find insertion point!');
  process.exit(1);
}

// Insert all new templates before the privacy injection line
content = content.slice(0, insertIdx) + allTemplates + '\n\n  ' + content.slice(insertIdx);

// Write back
fs.writeFileSync(filePath, content, 'utf8');
fs.appendFileSync('gen_debug.txt', '\nWRITTEN newLen=' + content.length);
console.log('SUCCESS: 50 templates (24-73) added. Total now 74.');
console.log('File size:', (content.length / 1024).toFixed(1), 'KB');
